112	  const linesTotal = sum(lines.map(linePremium));
113	  const policyBase = sum(lines.map((l) => l.base));
114	  const policyWideAdjustment = policyBase * policyWideRate(customer, quoteIndex);
115	  return roundUpInMHPCOFavor(linesTotal + policyWideAdjustment + PROCESSING_FEE);
116	};
117	
118	type Policy = { items: Item[]; cap: number };
119	
120	const createPolicy = (items: Item[]): Policy => {
121	  const insuranceSum = sum(items.map((item) => INSURANCE_VALUE[item.type]));
122	  return { items, cap: insuranceSum * CAP_MULTIPLIER };
123	};
124	
125	const damagePayout = (damage: Damage, item: Item): number => {
126	  const reimbursementRate = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
127	    ? HIGH_ENCHANTMENT_PAYOUT_RATE
128	    : 1;
129	  return Math.max(0, damage.amount * reimbursementRate - DEDUCTIBLE);
130	};
131	
132	const validateDamageAmounts = (damages: Damage[]): void => {
133	  for (const d of damages) {
134	    if (d.amount < 0) {
135	      throw new Error(`Damage amount must be non-negative: ${d.amount}`);
136	    }
137	  }
138	};
139	
140	const validateDamagesCoveredByPolicy = (damages: Damage[], policy: Policy): void => {
141	  const policyCounts = tallyBy(policy.items, (i) => i.type);
142	  const damageCounts = tallyBy(damages, (d) => d.itemType);
143	  for (const [type, count] of damageCounts) {
144	    if (count > (policyCounts.get(type) ?? 0)) {
145	      throw new Error(`Claim has more ${type} damages than insured`);
146	    }
147	  }
148	};
149	
150	const totalDamagePayout = (damages: Damage[], policy: Policy): number =>
151	  sum(damages.map((d) => {
152	    const item = policy.items.find((i) => i.type === d.itemType)!;
153	    return damagePayout(d, item);
154	  }));
155	
156	const processClaim = (step: ClaimStep, policies: Policy[]): ClaimResult => {
157	  const policy = policies[step.policy];
158	  const { damages } = step.incident;
159	  validateDamageAmounts(damages);
160	  validateDamagesCoveredByPolicy(damages, policy);
161	  const payout = Math.min(roundDownInMHPCOFavor(totalDamagePayout(damages, policy)), policy.cap);
162	  policy.cap -= payout;
163	  return { payout, remainingCap: policy.cap };
164	};
165	
166	export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
167	  const policies: Policy[] = [];
168	  const results: StepResult[] = scenario.steps.map((step) => {
169	    if (step.op === "quote") {
170	      const premium = computePremium(step, scenario.customer, policies.length);
171	      policies.push(createPolicy(step.items));
172	      return { premium };
173	    }
174	    return processClaim(step, policies);
175	  });
176	  return { results };
177	};
